import{_ as p,o as d,c as e,j as r,a,a1 as t}from"./chunks/framework.Bp7r_-XI.js";const B=JSON.parse('{"title":"苍天之龙骑士","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/苍天之龙骑士.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/苍天之龙骑士.md"}'),n={name:"4.资源分区/6.技艺及称号/武技类/白刃类/苍天之龙骑士.md"};function s(o,b,_,C,l,i){return d(),e("div",null,[...b[0]||(b[0]=[r("h1",{id:"苍天之龙骑士",tabindex:"-1"},[a("苍天之龙骑士 "),r("a",{class:"header-anchor",href:"#苍天之龙骑士","aria-label":'Permalink to "苍天之龙骑士"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),t('<h1 id="苍天之龙骑士-1" tabindex="-1">苍天之龙骑士 <a class="header-anchor" href="#苍天之龙骑士-1" aria-label="Permalink to &quot;苍天之龙骑士&quot;">​</a></h1><p>苍天之龙骑士</p><p>魔幻本质<br> 概述：屠龙之人，就是“龙骑士”。</p><p>对于宗教城邦伊修加德来说，因为自建国以来便一直处于和龙族没有尽头的战争中，所以这句话有着非常重要的意义。</p><p>为了打倒龙族，人们大力发展枪术，创造出了独特的跳跃攻击，专门瞄准隐藏在坚硬龙鳞之下的要害部位。龙骑士们跃入高空，与长枪化为一体，急坠而下——这份贯通力正是攻击的关键。</p><p>购买前置：所有的龙骑士技艺都需要购买至少1级枪术师（近战专长）后才能开放购买。</p><p>武器技艺：以下技艺仅能以长枪或造成物理-穿刺伤害的长柄武器发动。</p><p>连击状态：施展部分技艺会获得固定的一种连击状态，以【xx】状态进行表示；在具有连击状态时，发动对应技艺可以使招式获得连击强化，相对的，若没有施展可以发动连击的技艺，则会失去对应的连击状态。<br> 本资源下对于【龙】的定义为：体型在8以上的、具有膜状飞翼、覆有鳞片的二足或四足爬行类生物，当然，也可以简单理解成种族为龙的生物。</p><p>连招预览：</p><p>龙牙龙爪连段：精准刺（龙眼雷电）→贯通刺（前冲刺）→直刺（苍穹刺）→龙牙（龙牙龙爪）→云蒸龙变→龙眼雷电</p><p>龙尾大回旋连段：精准刺（龙眼雷电）→开膛枪（螺旋击）→樱花怒放（樱花缭乱）→龙尾大回旋→龙眼雷电</p><p>群攻连段：死天枪→音速刺→山境酷刑</p><p>后仰跳投连段：回避跳跃→贯穿尖</p><p>苍天龙血连段：苍天龙血（红莲龙血）→死者之岸</p><p>其它：强化技艺、整轮冲锋技艺。</p><p>D级：狩猎之枪术师<br> 价格：D+500<br> 描述：在黑衣森林中，猎食者与猎物不断磨砺自身的速度，只有比对方更快，才有一线生机；从中诞生的狩猎枪术，便是以极致的速度为核心。<br> 在以分类为【长枪】或其它造成物理-穿刺伤害的长柄武器进行战斗时视为以枪术进行战斗。<br> 在以枪术施展龙骑士技艺时，额外具有等同于自身传奇敏捷*2点高速，若这部分高速在破防后仍有剩余，可以将其中至多传奇敏捷点高速转为攻击上的速度加值。</p><p>龙骑士<br> 价格：C+1000<br> 描述：千年以前，人与龙的友谊与平衡被一己私念摧毁，那之后，精通枪术的骑士们在与龙的千年战争中不断磨炼自我，能以自身力量与翱翔天际的龙战斗的，名为龙骑士的职业如此传承下来。<br> 效果：当你进行攻击时，若在本轮内进行过移动或者跳跃，则在攻击上获得9加骰。每轮一次，当你面对受到【龙】的单位进行的攻击时，可以反射动作进行一次招架。</p><p>B级：雪原之龙骑士<br> 前提：枪术师3<br> 价格：B+2500<br> 描述：在库尔扎斯高原，冰天极地，精灵们与恶龙的千年龙诗，造就了在空中翱翔般的枪术技法。最终，龙骑士团以狩猎那些翱翔于天际的巨龙为目标，那骇人的咆哮将不再是危险的警告，而是通往胜利的号角。<br> 若在一次攻击前进行过移动，则每移动3米，这次攻击额外获得1dp速度加值，若为跳跃移动，则这次攻击前的移动中，在空中每下坠1米就会获得1dp速度加值，最多以此获益的加值上限等同于自身敏捷属性。<br> 每轮开始你获得2点AP以使用龙骑士技艺</p><p>苍天之龙骑士<br> 价格：A+4000<br> 苍天之龙骑士是所有龙骑士最终的目标，得到龙骑士称号者中最优秀的一名会被给予龙眼的力量，成为苍天之龙骑士，站在猎龙的最前线，这也是最强的龙骑士才能持有的称号。<br> 龙骑士拥有独特的方式对待龙种的进攻，每轮有一次机会，在承受来自种族为【龙】的攻击时，使那次攻击伤害减半。<br> 施展枪术攻击时，若那次攻击前龙骑士进行过移动，每移动3米都会使这次攻击额外具有1点附加成功，若为跳跃移动，则改为每在跳跃中下坠1米获益1附加成功，最多以此获益的附加成功上限为自身1/3力量属性点。<br> 每轮开始你额外获得2点AP以使用龙骑士技艺</p><p>龙骑士步法</p><p>回避跳跃<br> C+1000<br> 描述：在承受攻击前迅速向后跳走的技艺，是与巨龙周旋的能力。<br> 以一个移动动作进入【回避预备】状态，持续一轮，在拥有【回避预备】状态时，若你即将承受一次攻击，你可以立即消耗一个反射动作进行一次跳跃移动（这意味着需要预留一个反射动作至回合外）；这次跳跃可以向后或向左右任一方向进行，并且视为已经进行过助跑。<br> 在触发【回避预备】后，你获得【贯穿尖强化】效果：<br> 【贯穿尖强化】：下一次施展【贯穿尖】时，额外具有2dp技艺加值并使加骰提升一级（至多为8加骰），不可叠加。</p><p>龙翼滑翔<br> C+1000<br> 描述：通过龙血的力量暂时幻化出龙翼，在战场上快速机动的能力。<br> 这是一个移动技，无法与其他移动技共同生效。<br> 以一个移动动作进行加速冲刺，这次移动会在身体上幻化出蓝色的龙翼与龙形光效，速度之快就像平地飞行，但本质是一种迅速的冲刺移动方式而非真正的飞行移动，这次移动额外具有30+敏捷属性点*1米的移速加成，以此进行过移动的轮次内，反射豁免获得2dp技艺加值。</p><p>龙骑士祝福</p><p>战斗连祷<br> C+1000<br> 描述：龙骑士之间的默契与相互扶持的羁绊，最终化为了足以强化自身的唯心力量。<br> 以一个移动动作消耗2点意志发动，挥舞长枪，并发出振聋发聩的战吼，提振士气，同时，以自身为中心包括自身在内的15米范围内的所有友军获得持续一场景的【战斗连祷】状态。<br> 【战斗连祷】：拥有该效果的单位在攻击上获得施展该效果的单位的传奇决心*1dp士气加值与反射豁免上的1dp士气加值。<br> 攻击时，若这次检定出目在不计算附加成功与出目增益（如1.5倍出目）的情况下大于检定dp的一半，则这次攻击将额外附带1点不可豁免的流血点数与四分之一出目的麻痹点数，强韧豁免。</p><p>苍天龙血<br> B+2000<br> 描述：熟练地操纵龙血之力，将苍蓝的巨龙之力向前轰出，纠缠的龙血与历史将强化自身的架势，主动令龙血活化，从而换取更加强大的力量。<br> 以一个标准动作进行一次枪术攻击，这次攻击需要额外消耗3点意志力，这视为主动激活龙血时进行控制所必要的意志消耗。<br> 这次攻击将会在身前短暂地构造出巨龙之眼，随后以自身的龙血调动力量，一枪刺穿龙眼，龙眼中爆裂出的数条蓝色的巨龙虚影将缠绕在长枪上袭击敌人，但在施展时并没有实际的增益效果，在攻击之后，蓝色龙影咆哮着飞回，纳入龙骑士体内，龙血正式激活，身缠淡淡的蓝色龙之力，获得持续一场景的【苍天龙血】效果。<br> 施展该技艺后，你会获得【龙诗】状态。<br> 【苍天龙血】：这是一个持续一场景的增益效果，多次施展不会叠加效果强度。拥有该效果的龙骑士在战斗中的先攻视为额外提升16点，同时，在以枪术进行攻击时，可以令那次攻击加骰提升一级（至多为8加骰），运用龙血之力，龙骑士在一轮内有一次机会使得一次枪术攻击成功数增加一半。</p><p>————在具有苍天之龙骑士后，可以支付B+2000将该技艺差价技艺差价升级为【红莲龙血】，效果改为：<br> 【红莲龙血】：熟练地操纵龙血之力，将猩红的巨龙之力向前轰出，纠缠的龙血与尘封的历史将强化自身的架势，主动令龙血活化，从而换取更加强大的力量。<br> 以一个标准动作进行一次枪术攻击，这次攻击需要额外消耗4点意志力，这视为主动激活龙血时进行控制所必要的意志消耗。<br> 这次攻击将会附带有一条红色的巨龙虚影，但在施展时并没有实际的增益效果，在攻击之后，红色龙影纳入龙骑士体内，龙血正式激活，身缠浓郁的猩红龙血，获得持续一场景的【红莲龙血】效果。<br> 施展该技艺后，你会获得【龙诗】状态。<br> 【红莲龙血】：这是一个持续一场景的增益效果，多次施展不会叠加效果强度。拥有该效果的龙骑士在战斗中的先攻视为额外提升16点，同时，在以枪术进行攻击时，总是视为额外具有1L武器伤害与【湮灭】特性，可以令枪术攻击加骰提升一级（至多为8加骰），运用龙血之力，龙骑士在一轮内有一次机会使得一次枪术攻击检成功数增加一半。<br> 该状态下，若针对生物类型为【龙】的目标进行攻击，则攻击会额外附带S级重伤效果</p><p>龙骑士技艺<br> 当你购买了下列某一级别的龙骑士技艺后，此后每购买一次该级别龙骑士技艺，便会额外习得【已购买此级别龙骑士技艺次数-1】项该级别龙骑士技艺，额外习得的技艺不提供属性点，在计算购买招式的收益时，也不会将这部分赠送的招式计入其中。<br> 当你将某一级别龙骑士技艺进行差价升级时，也按照这一流程进行处理。即：购买了1个D级龙骑士技艺、一个C级龙骑士技艺，将D级招式差价升级后会额外赠送1项C级龙骑士技艺。</p><p>D级：</p><p>精准刺<br> D+500<br> 描述：连续戳出两枪试探，随后迅速探出一枪，精准地刺向要害。<br> 以一个标准动作，选择敌人的一个部位进行一次部位攻击，这次枪术攻击免去2点部位攻击减值；<br> 这次攻击额外具有2dp技艺加值与【高速5】，前两次试探将会造成2点多次攻击减值。<br> 施展该技艺会获得【精准】状态。<br> ——购买A级龙骑士技艺【云蒸龙变】后，可以将【精准刺】差价升级至A+4000的【龙眼雷电】，效果改为：<br> 【龙眼雷电】：在龙眼的力量加持下，最纯粹的技巧才具有了真正的力量，连续戳出数枪，依靠龙眼中的力量引发枪尖上的狂雷，随后如雷鸣出云，在一闪之间精准地刺向要害。<br> 以一个标准动作，选择敌人的一个部位进行一次部位攻击，这次枪术攻击免去2点部位攻击减值；<br> 这次攻击额外具有2dp技艺加值，通过雷光般的枪法，这次攻击无视对方的天生防御，这是一个A级创伤来源的忽略防御效果，前两次试探攻击只会造成2点多次攻击减值。<br> 施展该技艺会获得【精准】状态。<br> 若自身具有【龙眼】状态，则这次攻击将会触发连击；这次攻击在原有效果的基础上，如疾风暴雨，破空雷霆，倾泄而出。<br> 前两式如雷似电，互相穿插，连续不断地攻击敌人，这两式枪招共用同一次攻击检定，承受这次攻击的敌人需要针对这次攻击出目进行意志豁免，若豁免失败，则其承受A级创伤来源的【惊惧】异常状态；虚晃过后，以第三式全力刺出。<br> 第三式枪出如龙，全力一击，无需赘述，一枪，天地皆寂，仅此而已。这是一次全力枪术攻击，这次枪术攻击检定出目增加一半，附带攻击出目等量的四档流血点数。<br> 若【龙眼雷电】的攻击目标生物类型为【龙】，则这次攻击加骰额外提升一级（至多8加骰）并获得4点额外附加成功。<br> 特殊的，处于连击状态施展【龙眼雷电】不会获得【精准】状态。</p><p>贯通刺<br> D+500<br> 描述：运起全力，集中一点，贯穿敌人。<br> 以一个标准动作进行一次全力枪术攻击，集中攻击一点，提升1点附加成功与【破甲5】<br> 若自身具有【精准】状态，则这次攻击将会触发连击，额外具有1点附加成功与【贯穿】特性。<br> 连击状态下，施展该技艺会获得【贯通】状态。<br> ————支付D+500，该技艺差价升级为C级【贯通刺+】，效果改为：<br> 【贯通刺+】：以一个标准动作进行一次全力枪术攻击，集中攻击一点，提升1点附加成功与【破甲5】<br> 若自身具有【精准】状态，则这次攻击将会触发连击，额外具有2dp技艺加值和攻击上的1点附加成功，额外具有【超级贯穿】特性。<br> 连击状态下，施展该技艺会获得【贯通】状态。<br> ————支付C+1000，该技艺差价升级为B级【前冲刺】，效果改为：<br> 【前冲刺】：运起龙血，将力量集中一点，脚下发力的同时，一声龙吟，瞬息间贯穿敌人。<br> 以一个标准动作进行一次全力枪术攻击，集中攻击一点，提升1点附加成功与【破甲5】<br> 若自身具有【精准】状态，则这次攻击将会触发连击，额外具有2dp技艺加值和攻击上的1点附加成功，额外具有【8加骰】【超级贯穿】特性。<br> 在计算【超级贯穿】的效果后，若判定足以穿透目标，巨龙之力将会再次推进自身，立即向前方冲刺10米，同时穿刺攻击移动路径上，触及范围内的所有敌方单位。<br> 连击状态下，施展该技艺会获得【贯通】状态。</p><p>开膛枪<br> D+500<br> 描述：以枪为势，变化莫测，随枪势稍弱，但顺着施展的枪术摆开架势，令之后的攻击更加致命。<br> 以一个标准动作划出一枪，这次枪术攻击会承受4dp技艺减值。<br> 若自身具有【精准】状态，则这次攻击将会触发连击，攻击后摆出【开膛枪势】，这是一个架势技。<br> 连击状态下，施展该技艺会获得【开膛】状态。<br> 【开膛枪势】：该效果持续一场景，具有该效果时，发动的枪术攻击加骰提升一级（至多为8加骰），持续时间内枪势连绵不绝，以枪术进行的攻击额外具有【高速5】。<br> 重复施展该技艺不会叠加持续效果。<br> ————支付D+500，技艺差价升级为C级【开膛枪+】，该技艺效果改为：<br> 【开膛枪+】：以一个标准动作划出一枪，这次枪术攻击会承受6dp技艺减值。<br> 若自身具有【精准】状态，则这次攻击将会触发连击，在攻击后摆出【开膛枪势+】，这是一个架势技。<br> 连击状态下，施展该技艺会获得【开膛】状态。<br> 【开膛枪势+】：该效果持续一场景，具有该效果时，发动的枪术攻击加骰提升一级（至多为8加骰），持续时间内枪势连绵不绝，以枪术进行的攻击额外具有2dp高速加值与【高速5】，进行攻击时武器伤害额外提升1L。<br> 每轮一次，在进行枪术攻击检定时，可以重投一次，取其中较高的一次进行结算。<br> 重复施展该技艺不会叠加持续效果。<br> ————支付C+1000，技艺差价升级为B级【螺旋击】，该技艺效果改为：<br> 【螺旋击】：以枪为势，变化莫测，随枪势稍弱，但顺着施展的枪术摆开架势，令之后的攻击层层叠叠，更加致命。<br> 以一个标准动作消耗1点意志，向前刺出一枪，巨龙之力螺旋缠绕其上，这次枪术攻击会承受4dp技艺减值，在刺中敌人之后，巨龙虚影返回自身，将力量加持己身。<br> 若自身具有【精准】状态，则这次攻击将会触发连击，在攻击后摆出【螺旋枪势】，这是一个架势技。<br> 连击状态下，施展该技艺会获得【开膛】状态。<br> 【螺旋枪势】：该效果持续一场景，具有该效果时，武器上将会缠绕着不断转动的螺旋龙影，攻击时会高速旋转。发动的枪术攻击总是使加骰提升一级（至多为8加骰），持续时间内枪势连绵不绝，以枪术进行的攻击额外具有2dp高速加值与【高速5】，进行攻击时，武器伤害视为额外提升8L，获得4点额外附加成功。<br> 每轮一次，在进行枪术攻击检定时，可以重投一次，取其中较高的一次进行结算。<br> 重复施展该技艺不会叠加持续效果。</p><p>直刺<br> D+500<br> 描述：简单而纯粹的一击，却要调动全身力量，并且在各类枪式之后调整到最合适的位置与角度才能造成最为直接的伤害。<br> 以一个标准动作全力刺出一枪，这算作一次枪术全力攻击。<br> 若自身具有【贯通】状态，则这次攻击将会触发连击，全力攻击提供的全力攻击加值改为3dp，额外具有自身传奇力量点附加成功，每因此获得1点附加成功，都可以将这次攻击中的1dp转换为1点附加成功。<br> 连击状态下，施展该技艺会获得【直刺】状态。<br> ————支付D+500，技艺差价升级为C级【直刺+】，该技艺效果改为：<br> 【直刺+】：简单而纯粹的一击，却要调动全身力量，并且在各类枪式之后调整到最合适的位置与角度，随后一枪上挑，造成最为直接的伤害。<br> 以一个标准动作全力刺出一枪，这算作一次枪术全力攻击。<br> 若自身具有【贯通】状态，则这次攻击将会触发连击，额外具有【接触攻击】特性，全力攻击提供的全力攻击加值改为4dp，额外具有自身传奇力量点附加成功，每因此获得1点附加成功，都可以将这次攻击中的1dp转换为1点附加成功。<br> 连击状态下，施展该技艺会获得【直刺】状态。<br> ————支付C+1000，技艺差价升级为B级【苍穹刺】，该技艺效果改为：<br> 【苍穹刺】：纯粹的一击，却并不简单，需要调动全身的力量，在各类枪式之后调整到最合适的位置与角度，一枪上挑，巨龙之力几乎能撕破苍穹。<br> 以一个标准动作全力刺出一枪，这算作一次枪术全力攻击。<br> 若自身具有【贯通】状态，则这次攻击将会触发连击，额外具有【接触攻击】特性，全力攻击提供的全力攻击加值改为6dp，额外具有自身传奇力量点附加成功，每因此获得1点附加成功，都可以将这次攻击中的1dp转换为1点附加成功。<br> 投掷攻击检定，计算伤害吸收等伤害减免效果后，本次攻击的最终伤害将增加一倍。<br> 连击状态下，施展该技艺会获得【直刺】状态。</p><p>贯穿尖<br> D+500<br> 描述：汇聚力量，随后全力投掷武器的技法，在必要时会有意想不到的优势。<br> 以一个标准动作将手中的长枪投掷而出，进行投掷攻击检定，这也被视为一次枪术攻击，若这次投掷使武器落在了最大射程的一半以内，则可以立即以自由动作将其召回手中，若投掷落点超过最大射程的一半，则会在下轮开始时自动回到投掷时的原位，这是一个【回力】技法。<br> 这次攻击还额外具有【贯穿】特性与【高速5】。</p><p>龙剑<br> D+500<br> 描述：初步运用龙血，将战斗的鲜血化作自身持续战斗力量的技艺。<br> 以一个移动动作调动龙血，下一次进行全力攻击时，具有额外的2dp技艺加值，以枪术进行的攻击在计算破防与吸收后，每造成3点实际伤害就会为自身恢复1点完好或1点韧性，单次攻击至多恢复2点，这是来源于【吸血2】的恢复效果，这些恢复效果不能修复构造值，也不能因对构造体造成伤害而生效。<br> ——支付D+500，技艺差价升级为C级【龙枪+】，该技艺效果改为：<br> 【龙剑+】：以一个移动动作调动龙血，下一次进行全力攻击时，具有额外的2点附加成功，以枪术进行的攻击在计算破防与吸收后，每造成3点实际伤害就会为自身恢复1点完好或1点韧性，单次攻击至多恢复4点，这是来源于【吸血4】的恢复效果，这些恢复效果不能修复构造值，也不能因对构造体造成伤害而生效。<br> ——支付C+1000，技艺差价升级为B级【怒龙枪】，该技艺效果改为：<br> 【怒龙剑】：以一个移动动作调动龙血，下一次进行全力攻击时，具有额外的2dp技艺加值与2点附加成功，以枪术进行的攻击加骰提升一级（至多8加骰）；在计算破防与吸收后，每造成3点实际伤害就会为自身恢复1点完好或1点韧性，单次攻击至多恢复8点，这是来源于【吸血8】的恢复效果，这些恢复效果不能修复构造值，也不能因对构造体造成伤害而生效。</p><p>C级：</p><p>樱花怒放<br> C+1000<br> 描述：快速施展枪术，缭乱的枪花仿若樱花盛开，绽放出敌人的鲜血。<br> 以一个标准动作进行一次枪术攻击，附带1点不可豁免的流血点数。<br> 若自身拥有【开膛】状态，则这次攻击会触发连击，二分之一的伤害出目转化为创伤来源的剧痛点数，并额外附带有二分之一创伤来源的剧痛点数，以强韧豁免；命中后，若承受攻击的目标因这次攻击承受了剧痛点数，则这次攻击会再对其造成一次攻击，这次攻击不会造成伤害，而是造成1点多次攻击减值，附带1点不可豁免的流血点数。<br> 连击状态下，施展该技艺会获得【血花】状态。<br> ————支付C+1000，技艺差价升级为B级【樱花缭乱】，该技艺效果改为：<br> 【樱花缭乱】：快速施展枪术，缭乱的枪花仿若樱花盛开，绽放鲜血，在猩红的枪影中，置于死地。<br> 以一个标准动作进行一次枪术攻击，附带1点不可豁免的流血点数。<br> 若自身拥有【开膛】状态，则这次攻击会触发连击，额外具有【8加骰】；攻击伤害转化为创伤来源的流血点数，并额外附带有等量创伤来源的剧痛点数，皆以强韧豁免，承受差值负面点数；命中后，若承受攻击的目标因这次攻击承受了剧痛点数，则这次攻击会再对其造成两次攻击，这次攻击不会造成伤害，而是造成2点多次攻击减值，附带2点不可豁免的流血点数。<br> 当这次攻击的目标生物类型为【龙】时，攻击额外具有1点附加成功与1dp士气加值。<br> 连击状态下，施展该技艺会获得【血花】状态。</p><p>龙牙<br> C+1000<br> 描述：运用龙血的力量强化身体，运用枪术，将本就凌厉的攻势强化，模仿出龙之牙撕咬猎物的强大攻势。<br> 以一个标准动作进行一次枪术攻击，具有2dp技艺加值，附带1点不可豁免的流血点数。<br> 若自身拥有【直刺】状态，则这次攻击会触发连击，这次攻击额外具有【9加骰】与【超级贯穿】特性，并带有等同于自身1/4力量属性点的附加成功，每以此获得1点附加成功，都可以将攻击上的3dp转化为1点附加成功。<br> ————支付C+1000技艺差价升级为B级【龙牙龙爪】，该技艺效果改为：<br> 【龙牙龙爪】：运用龙血的力量强化身体运用枪术，将本就凌厉的攻势强化，模仿出龙之牙撕咬猎物、龙之爪摧毁敌人的强大攻势。<br> 以一个标准动作进行一次枪术攻击，具有2dp技艺加值，附带1点不可豁免的流血点数。<br> 若自身拥有【直刺】状态，则这次攻击会触发连击，这次攻击先连续进行两次挥砍，这两次攻击不会造成伤害，转而造成2点多次攻击减值，随后一枪刺出，这一击具有【8加骰】与【超级贯穿】特性，并带有等同于自身1/4力量属性点的附加成功，每以此获得1点附加成功，都可以将攻击上的3dp转化为1点附加成功，进行转化时，前4点附加成功可以将1dp转化为1点附加成功，之后的转化遵循3dp转化规则。<br> 若进行这次连击时，你在攻击目标的两侧，则这次攻击将额外具有【接触攻击】特性，额外获得2点攻击上的附加成功。<br> 连击状态下，施展该技艺会获得【龙变】状态。</p><p>跳跃<br> C+1000<br> 描述：高高跃起，自上而下地进行穿刺，是可以命中龙族要害的枪术，也是龙骑士的标志技艺。<br> 以一个整轮动作进行枪术冲锋，特殊的是，这次冲锋的移动为跳跃移动，视为已经助跑，并且不会承受基础防御减值；在计算移动距离时，尽可能地跳跃到最高点，并从上至下对敌人进行下坠攻击，这次攻击前每在下坠的过程中移动了1米，就在攻击上获得1点附加成功，以此获益的上限为1/4力量属性点（向下取整）。<br> ————支付C+1000后，技艺差价升级为B级【高跳】，该技艺效果改为：<br> 【高跳】：高高跃起，自上而下地进行穿刺，是可以命中龙族要害的枪术，只有最为老练的龙骑士可以精准地把控自身在空中的行动，并将枪术融入其中，精准致命，也是龙骑士的标志技艺。<br> 以一个整轮动作进行枪术冲锋，特殊的是，这次冲锋的移动为跳跃移动，视为已经助跑，并且不会承受基础防御减值；在计算这次移动距离时，移速额外提升20米，尽可能地跳跃到最高点，并从上至下对敌人进行下坠攻击，这次攻击具有额外1点附加成功，并使加骰提升一级（至多为8加骰），攻击前每在下坠的过程中移动了1米，就在攻击上再获得1点附加成功，以此获益的上限为1/2力量属性点（向下取整）。<br> 在计算伤害吸收时，这次攻击的伤害会无视1点近战伤害吸收</p><p>死天枪<br> C+1000<br> 描述：汇聚龙血之力，将枪意刺出，远程伤敌。<br> 以一个标准动作进行一次枪术攻击，这次攻击向目标所在方向发出直线范围物理穿刺攻击，枪意化作三道龙爪，自下而上地抓向敌人敌人，枪意的宽度为5米，最远射程可达20米，攻击范围内的敌人以反射豁免，承受差值的物理-穿刺伤害，这次攻击具有2dp技艺加值与【贯穿】特性，额外造成1点多次攻击减值。<br> 施展该技艺后，你会获得【死天】状态。</p><p>龙炎冲<br> C+1000<br> 描述：通过龙血的力量将龙息附着在长枪上，自上而下地坠击敌人，引发剧烈的爆炸与燃烧。<br> 以一个整轮动作进行枪术冲锋，特殊的是，这次冲锋的移动为跳跃移动，视为已经助跑，在计算移动距离时，尽可能地跳跃到最高点，并从上至下裹挟着高温龙息对敌人进行下坠攻击，在抵达落点后，龙息迅速反应以自身为中心产生爆炸，自身触及范围内的所有敌人以反射豁免，承受豁免差值的火焰伤害，在这次攻击中承受伤害的目标将额外收到1点不可豁免的燃烧负面点数。<br> ————支付C+1000，技艺差价升级为B级【龙焱冲】，该技艺效果改为：<br> 【龙焱冲】：熟练地运用龙血，将龙息包裹全身，喷发至高空，随后如龙息流火般坠下，引发剧烈的爆炸与燃烧。<br> 以一个整轮动作冲锋，特殊的是，这次冲锋的移动为跳跃移动，视为已经助跑，在计算移动距离时，尽可能地跳跃到最高点，并从上至下裹挟着高温龙息对敌人进行下坠攻击，这次冲锋攻击的有效距离自动取最大值计算，在抵达落点后，龙息迅速反应以自身为中心产生剧烈喷发反应，自身触及范围内的所有敌人以反射豁免，承受豁免差值的燃烧异常点数。</p><p>B级：</p><p>龙尾大回旋<br> B+2000<br> 描述：通过离心力造成大范围斩击的技艺，如巨龙的尾巴一般横扫，使敌人破绽，在那之后找准时机瞬间突刺的强力技艺。<br> 仅在自身拥有【血花】状态时可以施展，这次攻击视为触发连击，先以长枪环扫自身，如龙尾横扫，对敌人造成物理-挥砍伤害，承受这次攻击伤害的单位，以这次攻击的伤害为豁免dc进行强韧豁免，若豁免失败，则承受等同于龙骑士力量属性的【物理-穿刺】伤害易伤，持续一轮。<br> 那之后，立即调转枪身，向前一枪刺出，追加进行一次攻击检定，这次攻击如常造成物理-穿刺伤害，额外提升2L武器伤害，并具有【幻灭】特性。<br> 施展该技艺后，你会获得【龙变】状态。<br> 连击状态下，施展该技艺会获得【龙变】状态。</p><p>龙炎升<br> B+2000<br> 前置：施展过【龙炎冲（龙焱冲）】才能释放<br> 描述：将龙息之力打入脚下，以枪法上挑的同时将龙之力幻化为咆哮的巨龙，吞噬面前的敌人。<br> 以一个标准动作进行一次枪术攻击，伴随着枪术的施展，咆哮的龙影从地下钻出飞向上空，这次攻击额外附带B级措手不及效果，不造成伤害，转而造成攻击出目等量的燃烧异常点数，强韧豁免，龙影在那之后伴随枪势向下轰击，随后砸入地面，留下焦灼开裂的痕迹，若目标因这次攻击承受了燃烧异常点数，则额外附带2点不可豁免的燃烧点数。</p><p>幻象冲<br> B+2000<br> 前置：施展过【跳跃（高跳）】才能释放<br> 描述：将龙息之力在体内运转，幻化出蓝色的巨龙虚影咆哮升空，旋即自上而下地飞向敌人，吞噬面前的敌人。<br> 以一个标准动作进行一次枪术攻击，这次攻击不以枪术造成实际伤害，而是将这次攻击的伤害记录下来，保存在体内幻化的巨龙虚影当中，在攻击检定结束后，巨龙虚影旋即飞出，直冲天空，然后调转龙头，飞向60M范围内的选定的一个敌人，正常计算破防与伤害减免，这次攻击如被龙撕咬般造成物理-穿刺伤害，带有【湮灭】【幻灭】特性，在这次枪术攻击检定中，不计算附加成功与出目相关的增益，这次检定的自然成功数大于dp数值的一半，则这次攻击在计算破防与伤害吸收等效果过后，造成的实际伤害增加一倍，同时，可以将这次伤害中的2L转化为2A。</p><p>音速刺<br> B+2000<br> 描述：纯粹的枪术技艺，连续不断地戳刺前方，速度之快甚至足以突破音障，使得每一枪都能爆发出刺耳的音爆。<br> 以一个标准动作进行一次枪术攻击，以自身触及范围作为射程，向前方120°扇形范围施展超越音速的连续戳刺，由于速度过快，没办法准确地避开攻击范围内的敌人，故此无法分辨敌我，在施展时需要小心误伤队友。<br> 若自身具有【贯通】状态，则这次攻击将会触发连击，额外具有【超级贯穿】【9加骰】特性，这次攻击拥有额外的【破甲5】，同时无视闪避防御，这是由于纯粹的高速导致的B级创伤来源无视防御效果。<br> 连击状态下，施展该技艺会获得【音速】状态。</p><p>A级：</p><p>云蒸龙变<br> A+4000<br> 描述：龙血，是龙的力量载体，它们拖拽着巨龙的精华，这一招式是真正与龙血相融洽的龙骑士才能施展的绝强攻击，在攻击时，每一击都会幻化出始源巨龙的虚影，似爪似牙，似翼似尾，蒸腾的龙血甚至会让龙骑士的身体快速代谢，产生的高温足以将汗液汽化，化作阵阵白雾，结合在枪术中，正如巨龙翻雾，腾龙降云。<br> 仅在自身拥有【龙变】状态下可以使用，这次攻击视为连击；以一个标准动作进行一次枪术攻击，攻击分为两部分，第一部分是以枪术调用龙血，令接下来的连续攻击模仿出巨龙的爪击，对自身触及范围内的所有敌人进行一次利爪穿刺攻击，这次攻击将附带等量的四档流血点数。<br> 第二部分是将龙血之力汇聚于枪尖，旋即一枪刺出，咆哮的巨龙裹挟着高温白雾枪意向着正前方扑袭而去，对前方直线造成范围攻击，最远距离达80米，宽20米，这次攻击将附带等量的四档燃烧点数。<br> 连击状态下，施展该技艺会获得【龙眼】状态。</p><p>山境酷刑<br> A+4000<br> 描述：在高山雪原之上，龙骑士们必须要适应在严寒中的残酷环境，保持肉体的活性进行战斗，如此磨炼而出的，是名为山境酷刑的大范围群攻连击。<br> 仅在自身拥有【音速】状态下可以使用，这次攻击视为连击；以一个标准动作进行一次枪术攻击，这次攻击将对自身前方锥形120°范围内的所有敌人造成范围攻击伤害，无数的枪影与横扫席卷而出，伴随着龙影盘旋，这次攻击的最远距离可达300米，附带等量的流血异常点数与冰冻异常点数，以强韧豁免。<br> 若承受了这次攻击的单位在进行豁免后依然因此同时承受了流血与冰冻异常点数，需要额外对这次攻击出目再进行一次意志豁免，若豁免失败，则攻击中产生的龙影会顺势钻入其体内，额外使其承受A级附身来源的【耗竭】与【狂躁】负面效果。</p><p>死者之岸<br> A+4000<br> 前置：苍天龙血<br> 描述：龙眼，是龙的力量源泉，蕴含着巨龙的本源与灵魂；这一招式是真正与龙血相融洽的龙骑士才能施展的绝强攻击，在自身与敌人之间幻化出数颗龙眼，牢牢锁定敌人，旋即一枪刺出，将所有龙眼的虚影刺破，猩红的龙之力裹挟成枪，席卷敌人。<br> 这敌人与龙骑间的龙眼虚影，就是生与死的隔阂。<br> 仅在自身拥有【龙诗】状态下可以使用，这次攻击视为连击；以一个标准动作，对敏感范围内的一名敌人进行一次枪术攻击，先记录这次枪术攻击的出目，这次攻击的出目中每具有20点成功数，就会在自身与目标间创造出1颗龙眼，至多为7颗，；被龙眼锁定的目标以意志豁免，若豁免失败，其陷入一轮A级影响心灵来源的【定身】异常效果，旋即，这一次枪术攻击的枪意将所有龙眼全部击穿，化作猩红的长枪刺穿敌人造成伤害，相对的，若敌方因任何原因免疫了这次定身效果，后续的效果与攻击自然也会失去。<br> 这次锁定记录的攻击出目，若在不计算附加成功、出目翻倍等出目改动效果的情况下，出目大于检定dp的一半，这次攻击造成的伤害在计算破防与伤害减免后额外增加两倍；承受这次翻倍伤害攻击的目标生物类型为【龙】的情况下，目标将立即承受影响心灵来源的A级即死效果，即使目标并未因此死亡，也会需要针对这次攻击伤害额外进行一次意志豁免，若此次意志豁免未能通过，目标将因此承受A级影响心灵来源的【震慑】与【耗竭】异常负面效果。</p><p>坠星冲<br> A+4000<br> 描述：如一颗坠落的晨星，燃尽自身，也要杀尽敌人。<br> 以一个整轮动作进行枪术冲锋，特殊的是，这次冲锋的移动为跳跃移动，视为已经助跑，在计算移动距离时，仅针对跳跃高度额外提高200米，此时，尽可能地跳跃到最高点，并从高空锁定目标敌人，在自身与目标之间创造出七个花纹繁复的猩红螺旋法阵，法阵会牢牢锁定敌人，那之后，一跃而下，踏碎所有的法阵，每踏碎一层，都会使得接下来的冲锋散发出更加耀眼的红光，最终如一颗坠落的流星，轰然砸向地面；这次冲锋攻击会在抵达落点时对目标进行攻击，正常计算破防；就算锁定目标逃出冲锋范围也无济于事，依然可以按照脱离攻击范围一般进行冲锋攻击，若有敌人拦在自身与锁定目标之间，则会对所有在冲锋过程中接触的敌方单位造成攻击伤害。<br> 这次攻击会具有【8加骰】【超级贯穿】特性，在计算攻击检定时，这次攻击可以额外加入决心作为检定属性，并正常获得对应加值。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',52)])])}const A=p(n,[["render",s]]);export{B as __pageData,A as default};
